class Solution {
    public int findIntegers(int n) {
        int count = 0;
        for (int i = 0; i <= n; i++) {
            int binary = Integer.toBinaryString(i);
            boolean hasConsecutiveOnes = false;
            for (int j = 0; j < binary.length(); j++) {
                if (binary.charAt(j) == '1' && (j + 1 < binary.length() && binary.charAt(j + 1) == '1')) {
                    hasConsecutiveOnes = true;
                    break;
                }
            }
            if (!hasConsecutiveOnes) {
                count++;
            }
        }
        return count;
    }
}
